BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?nestedPkg ?nestedName ?diagram ?diagName WHERE {
  ?pkg vocab:NamedElement_name "Pupil%20Alignment%20Error%20Budget" .
  ?pkg rdf:type vocab:package .
  OPTIONAL {
    ?pkg vocab:Package_nestedPackage ?nestedPkg .
    OPTIONAL { ?nestedPkg vocab:NamedElement_name ?nestedName }
  }
  OPTIONAL {
    ?pkg vocab:Namespace_ownedDiagram ?diagram .
    OPTIONAL { ?diagram vocab:NamedElement_name ?diagName }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?block ?prop ?val WHERE {
  VALUES ?block {
    <TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::10%2520Analysis::Roll-up%2520Analyses::Error%2520Budgets::Pupil%2520Alignment%2520Error%2520Budget::Knowledge%2520of%2520APT-TMT%2520interface%2520point>
  }
  ?block ?prop ?val .
}
LIMIT 25
